#!/usr/bin/env python3
"""Third batch of SFT training data to reach ~800 total examples."""

import json
import os

OUTPUT_DIR = os.path.join(os.path.dirname(__file__), "raw")
SYSTEM_PROMPT = "You are a ransomware forensic analyst with deep expertise in Windows internals and incident response."
GENERATED_AT = "2026-03-17T11:00:00Z"
GENERATOR_MODEL = "claude-opus-4-6"


def make_example(source, source_url, source_section, example_type, topics,
                 prompt_id, user_content, assistant_content):
    return {
        "messages": [
            {"role": "system", "content": SYSTEM_PROMPT},
            {"role": "user", "content": user_content},
            {"role": "assistant", "content": assistant_content},
        ],
        "metadata": {
            "source": source,
            "source_url": source_url,
            "source_section": source_section,
            "example_type": example_type,
            "topics": topics,
            "generation_prompt_id": prompt_id,
            "generated_at": GENERATED_AT,
            "generator_model": GENERATOR_MODEL,
            "quality_score": None,
        },
    }


def append_jsonl(filename, examples):
    path = os.path.join(OUTPUT_DIR, filename)
    with open(path, "a") as f:
        for ex in examples:
            f.write(json.dumps(ex, ensure_ascii=False) + "\n")
    return len(examples)


def gen_cisa_batch3():
    S, U = "cisa_stopransomware", "https://www.cisa.gov/stopransomware/ransomware-guide"
    P, PI, PP = "cisa_qa_v3", "cisa_instruction_v3", "cisa_passage_v3"
    ex = []
    m = lambda s,e,t,p,q,a: ex.append(make_example(S,U,s,e,t,p,q,a))

    data = [
        # Incident response procedures
        ("Response Checklist","qa",["containment_decision","incident_response"],P,"When should an incident commander decide to shut down the entire network during a ransomware incident?","Full network shutdown is a last resort when: encryption is actively spreading and cannot be contained through targeted isolation; the ransomware has reached domain controllers and is deploying via Group Policy; the propagation mechanism cannot be identified quickly enough to implement targeted blocks; or life-safety systems in critical infrastructure environments are at risk. Before full shutdown, attempt: isolating affected VLANs at the core switch, blocking SMB/RDP/WMI at host firewalls via EDR push, and disabling the spreading mechanism (e.g., deleting the malicious GPO, stopping the PsExec deployment script). Full shutdown consequences include: loss of volatile evidence (encryption keys in memory), extended recovery time (all systems must be verified clean before reconnection), business disruption across all operations, and potential complications with systems that do not restart cleanly after hard shutdown. If shutdown is necessary, capture memory from at least the most critical systems before disconnecting power."),
        ("Response Checklist","qa",["business_continuity","incident_response"],P,"How should business continuity procedures integrate with ransomware incident response?","Business continuity activation should occur in parallel with technical response. Key integration points include: pre-identified manual workarounds for critical business processes (paper-based ordering, phone-based customer service, manual financial transactions) that activate when IT systems are unavailable; a prioritized recovery list mapping business processes to IT systems, with Recovery Time Objectives (RTOs) driving the order of system restoration; communication procedures for customers, partners, and suppliers that do not rely on potentially compromised email systems; alternative payment processing if financial systems are affected; and pre-arranged agreements for temporary IT infrastructure (cloud-based email, temporary file sharing) to maintain minimum business operations. The incident commander should coordinate with business continuity leadership to: assess which business processes are impacted, estimate recovery timelines based on the technical assessment, and make decisions about when to activate each continuity procedure. Testing should include combined ransomware/business continuity exercises annually."),
        ("Prevention Best Practices","qa",["identity_protection","mfa_fatigue"],P,"How should organizations defend against MFA fatigue attacks used as a ransomware initial access technique?","MFA fatigue (also called MFA bombing or push notification spam) involves sending repeated push notification MFA prompts to a user until they approve one out of frustration. Defense measures include: implementing number-matching MFA that requires the user to enter a code displayed on the login screen (eliminating the simple approve/deny prompt); configuring rate limiting on MFA push notifications (maximum 3 prompts per hour); implementing Microsoft Authenticator's additional context feature showing the application name and geographic location of the login attempt; migrating to FIDO2/WebAuthn hardware keys that are immune to fatigue attacks; configuring alerts when a user receives more than 5 MFA prompts within 10 minutes; training users to report unexpected MFA prompts and never approve requests they did not initiate; and implementing conditional access policies that block authentication attempts from suspicious locations or non-compliant devices before MFA is even prompted. The Uber breach in September 2022 demonstrated how effective MFA fatigue can be, highlighting the need for phishing-resistant MFA methods."),
        ("Prevention Best Practices","qa",["windows_firewall","host_isolation"],P,"How should Windows host-based firewall be configured to limit ransomware lateral movement?","Windows Firewall with Advanced Security should be configured via Group Policy to restrict inbound connections that enable lateral movement. Key rules: block inbound SMB (TCP 445) on all workstations (workstations should not accept SMB connections from other workstations); block inbound RDP (TCP 3389) on workstations except from designated admin jump servers; block inbound WMI (TCP 135 + dynamic ports) and WinRM (TCP 5985/5986) on workstations; allow these ports on servers only from authorized management subnets. Configure the firewall in all three profiles (Domain, Private, Public) to maintain protection regardless of network detection. Enable firewall logging for dropped connections to C:\\Windows\\System32\\LogFiles\\Firewall\\pfirewall.log, configuring log rotation to prevent disk space issues. Deploy rules using GPO with merge mode to combine centrally managed rules with any application-specific rules. Test rules in audit mode by enabling logging without blocking, then review logs for legitimate traffic that would be affected before enforcing blocks. The goal is to make each workstation an island that can communicate with authorized servers but cannot directly connect to other workstations."),
        ("Prevention Best Practices","qa",["ad_tiering","privilege_management"],P,"Explain the Microsoft tiered administration model for Active Directory and how it prevents ransomware escalation.","The tiered administration model segregates administrative privileges into three tiers to prevent credential theft from propagating across the environment. Tier 0 (Domain controllers and identity): contains domain controllers, AD FS, PKI infrastructure, and the management tools for these systems. Tier 0 admin accounts never authenticate to lower-tier systems. Tier 1 (Servers): contains member servers, applications, and cloud services. Tier 1 admin accounts manage servers but never authenticate to domain controllers or workstations. Tier 2 (Workstations and devices): contains user workstations and mobile devices. Tier 2 admin accounts (helpdesk, desktop support) only authenticate to workstations. For ransomware prevention: if an attacker compromises a workstation and captures the Tier 2 admin credentials from LSASS memory, these credentials cannot be used to access servers or domain controllers, stopping the kill chain at the workstation tier. Implementation requires: separate admin accounts per tier (admin-t0-jsmith, admin-t1-jsmith, admin-t2-jsmith), Privileged Access Workstations (PAWs) for Tier 0 administration, authentication policies restricting where each tier's accounts can authenticate, and monitoring for tier-crossing authentication attempts."),
        ("Forensic Investigation","qa",["event_id_4662","directory_service"],P,"How do you use Event ID 4662 to detect DCSync attacks during ransomware investigations?","Event ID 4662 (Directory Service Access) records operations on AD objects and is critical for detecting DCSync attacks. DCSync uses the Directory Replication Service (DRS) protocol to request password hashes from a domain controller, mimicking normal replication. Detection: filter Event ID 4662 for operations where the 'Properties' field contains the GUIDs for DS-Replication-Get-Changes (1131f6aa-9c07-11d1-f79f-00c04fc2dcd2) and DS-Replication-Get-Changes-All (1131f6ad-9c07-11d1-f79f-00c04fc2dcd2). The 'Subject' field identifies the account performing the replication. Critical check: the SubjectUserName should be a domain controller machine account (DC$); if it is a user account or a non-DC computer account, this indicates a DCSync attack using tools like Mimikatz 'lsadump::dcsync' or Impacket's secretsdump.py. Cross-reference with Event ID 4624 to identify the source system of the account performing DCSync. Additionally, monitor for Event ID 4742 (computer account changed) targeting the 'Replicating Directory Changes' permission being added to non-DC accounts."),
        ("Forensic Investigation","qa",["event_id_1102","anti_forensics"],P,"What does Event ID 1102 indicate and how do you investigate when event logs have been cleared?","Event ID 1102 in the Security log records that the Security event log was cleared, including the account name, domain, and logon ID of the user who cleared it. This is a strong anti-forensic indicator: ransomware operators frequently clear event logs before or after key attack phases to destroy evidence. Investigation when logs are cleared: first check the Event ID 1102 record itself (it is the one event that survives clearing since it is generated by the clearing action); note the timestamp and account to establish when and who cleared the logs. Alternative evidence sources: Windows Event Forwarding (WEF) collector maintains copies of forwarded events that survive local clearing; SIEM retains ingested events independently; Sysmon logs in a separate event channel may not have been cleared; the Security.evtx file in the Windows.old directory if the system was recently upgraded; PowerShell Operational log and other non-Security channels may retain evidence; and even cleared event log files may leave recoverable artifacts in the $UsnJrnl (the deletion and recreation of the .evtx file is recorded) and in unallocated disk space where the old log data may be recoverable through file carving."),
        ("Forensic Investigation","qa",["golden_ticket","kerberos_forensics"],P,"How do you detect Golden Ticket attacks used by ransomware operators for persistent domain access?","Golden Ticket detection is challenging because the forged ticket is indistinguishable from a legitimate one in most log sources. Detection approaches: Event ID 4769 (service ticket request): Golden Tickets use a forged TGT to request service tickets; look for service ticket requests where the account name does not match any current user account, or where the domain SID in the ticket does not match the current domain. Event ID 4624: logon events generated by Golden Ticket usage show Logon Type 3 (Network) with Kerberos authentication, but the logon may come from unexpected source systems. Ticket lifetime anomaly: Golden Tickets are typically created with extended lifetimes (years); the MaxTicketAge in the Kerberos policy is 10 hours by default, so a TGT with a longer lifetime indicates a forged ticket. Event ID 4768 absence: legitimate Kerberos authentication generates a 4768 (TGT request) followed by 4769 (service ticket request); Golden Tickets skip the 4768 step since the TGT is forged, so service ticket requests without a preceding TGT request from the same account are suspicious. KRBTGT password age: check when the KRBTGT password was last reset; if the current password has been unchanged since before the incident started, assume all Kerberos tickets are potentially compromised and perform a double KRBTGT reset."),
        ("Prevention Best Practices","qa",["sysmon_deployment","monitoring_strategy"],P,"What Sysmon configuration should organizations deploy for ransomware detection?","A ransomware-focused Sysmon configuration should capture high-value events while minimizing noise. Essential events to enable: Event ID 1 (Process Creation) with full command-line logging - this is the single most important detection source; Event ID 3 (Network Connection) for outbound connections from non-browser processes to detect C2 and exfiltration; Event ID 7 (Image Loaded) filtered to unsigned DLLs or DLLs loaded from unusual paths to detect DLL side-loading; Event ID 8 (CreateRemoteThread) to detect process injection by Cobalt Strike and other frameworks; Event ID 10 (ProcessAccess) filtered to TargetImage containing lsass.exe for credential theft detection; Event ID 11 (FileCreate) filtered to sensitive directories (\\Windows\\System32\\, \\Windows\\Tasks\\) for persistence detection; Event ID 12/13/14 (Registry events) filtered to Run keys, Services, and other persistence locations; Event ID 17/18 (Pipe Created/Connected) for Cobalt Strike named pipe communication; and Event ID 22 (DNSQuery) for C2 domain resolution tracking. Use the SwiftOnSecurity sysmon-config or Olaf Hartong's sysmon-modular as a starting baseline, then customize based on your environment. Deploy Sysmon via GPO and ensure the event channel is forwarded to your SIEM."),
        ("Response Checklist","instruction",["ransomware_variant_identification","forensic_triage"],PI,"Walk through the process of identifying a ransomware variant from available forensic evidence.","Ransomware variant identification follows a multi-step process. Step 1 - Ransom note analysis: examine the ransom note text, formatting, and demands; use ID Ransomware (id-ransomware.malwarehunterteam.com) by uploading the note and a small encrypted file sample. Step 2 - File extension: identify the extension appended to encrypted files; many families use distinctive extensions (.lockbit, .basta, .akira, .play, .royal, .alphv). Step 3 - Ransom note filename: the note filename is often family-specific (Restore-My-Files.txt for LockBit 2.0, HOW_TO_DECRYPT.txt for Hive, README.txt for Black Basta, akira_readme.txt for Akira). Step 4 - Binary analysis: if the ransomware binary is recovered, compute its SHA256 hash and check VirusTotal for identification; examine PE metadata (Rust compilation for BlackCat/Akira, Go for Hive v1-v4, C++ for most others); extract embedded configuration data. Step 5 - Desktop wallpaper: some families change the wallpaper to a distinctive ransom message. Step 6 - Tor/payment infrastructure: the ransom note typically contains a Tor URL; the URL structure and site design identify the group. Step 7 - MITRE ATT&CK mapping: map observed TTPs to group profiles for attribution confidence."),
        ("Prevention Best Practices","qa",["secure_admin_workstation","paw"],P,"What is a Privileged Access Workstation (PAW) and how does it prevent ransomware escalation?","A Privileged Access Workstation (PAW) is a hardened workstation dedicated exclusively to performing administrative tasks for Tier 0 systems (domain controllers, AD, PKI). PAW design principles: the PAW runs a clean OS build with application allowlisting, is not used for email, web browsing, or general productivity (eliminating phishing and web-based compromise vectors); it connects only to Tier 0 management networks; it requires hardware token (FIDO2) authentication; it uses a separate, hardened administrative account; and it is monitored with enhanced audit logging. For ransomware prevention: even if an attacker fully compromises the corporate network, they cannot access Tier 0 systems without compromising a PAW, which is significantly harder due to its reduced attack surface and enhanced monitoring. PAW deployment options: dedicated physical hardware (highest security), Privileged Access feature in Windows (using Credential Guard with hardware isolation), or Azure AD joined devices with conditional access policies restricting Tier 0 access. Combined with the tiered administration model, PAWs ensure that domain admin credentials never exist on systems where they could be captured by an attacker who has compromised a workstation or member server."),
        ("Response Checklist","qa",["incident_documentation","forensic_reporting"],P,"What should a ransomware incident response report include?","A comprehensive ransomware IR report should contain: Executive Summary: brief description of the incident, scope of impact, business disruption duration, and key findings. Timeline: chronological reconstruction of the attack from initial access through containment, with timestamps for each significant event. Root Cause Analysis: how the attacker gained initial access, what vulnerability or weakness was exploited, and what security controls failed to detect or prevent the attack. Scope of Compromise: number and list of affected systems, accounts compromised, data accessed or exfiltrated, and the encryption scope. Technical Findings: detailed analysis of malware samples, IOCs extracted, MITRE ATT&CK techniques observed, and forensic artifact analysis results. Response Actions: containment measures implemented, eradication steps performed, and recovery procedures followed, with timestamps. Data Breach Assessment: whether data was exfiltrated, what categories of data were affected, number of records, and individuals impacted. Recommendations: immediate (patch the initial access vector), short-term (detection improvements, hardening), and long-term (architecture changes, program improvements). Appendices: IOC list, affected system inventory, evidence chain of custody records, and communication log."),
        ("Prevention Best Practices","qa",["incident_readiness","security_baseline"],P,"What security baseline controls should every organization have before a ransomware incident occurs?","Essential pre-incident baseline controls include: (1) EDR on all endpoints including servers with tamper protection enabled. (2) Centralized logging to a SIEM with minimum 90-day retention for Security, PowerShell, and Sysmon event logs. (3) MFA on all external-facing services (VPN, email, cloud apps). (4) Tested offline or immutable backups with documented recovery procedures. (5) Network segmentation separating workstations from servers and isolating backup infrastructure. (6) Patching SLA of 14 days for internet-facing systems and 30 days for internal systems. (7) Incident response plan with designated roles, communication templates, and contact information for legal, IR firm, and law enforcement. (8) Asset inventory tracking all internet-facing services and internal critical systems. (9) Privileged access management with separate admin accounts and restricted Domain Admin usage. (10) Email security with attachment filtering, link rewriting, and DMARC enforcement. These ten controls address the most common ransomware attack paths and provide the foundation for effective incident response when prevention fails."),
        ("Forensic Investigation","qa",["cobalt_strike_config","c2_analysis"],P,"How do you extract and analyze a Cobalt Strike beacon configuration from a memory dump?","Cobalt Strike beacon configurations can be extracted from memory dumps to identify C2 infrastructure and operational parameters. Extraction tools: CobaltStrikeParser (SentinelOne/Didier Stevens) scans raw memory or process dumps for beacon configurations; 1768.py (Didier Stevens) identifies and extracts CS configurations from various file formats; and MemProcFS can identify Cobalt Strike beacons in live memory. Configuration data includes: C2 server addresses and ports; beacon type (HTTP, HTTPS, DNS, SMB); sleep time and jitter percentage; user-agent string; URI paths for GET and POST communications; named pipe name for SMB beacons; watermark (license-specific identifier); malleable C2 profile indicators; process injection methods configured; and spawn-to binary paths. Analysis value: C2 server addresses become IOCs for network-level blocking and threat intelligence sharing; the watermark can attribute the beacon to a specific Cobalt Strike license holder (though cracked versions use modified watermarks); the malleable profile reveals which network signatures to search for in traffic analysis; and spawn-to settings show which processes the operator will inject into. Extract from specific process memory using Volatility 3: windows.memmap --pid <beacon_pid> to dump the process, then run CobaltStrikeParser against the dump."),
        ("Prevention Best Practices","qa",["laps_deployment","local_admin"],P,"How does LAPS (Local Administrator Password Solution) prevent ransomware lateral movement and how should it be deployed?","LAPS randomizes and manages the local administrator password on every domain-joined machine, preventing an attacker who captures one local admin password from using it to access any other system. Without LAPS: organizations often deploy the same local admin password across all workstations via Group Policy Preferences or imaging, meaning one compromised password provides admin access to every system. With LAPS: each system has a unique, randomly generated local admin password stored in a confidential attribute of its AD computer object, readable only by authorized administrators. Deployment: install the LAPS CSE (Client-Side Extension) on all managed systems via GPO or SCCM; configure the LAPS GPO specifying password length (minimum 20 characters), complexity requirements, and rotation interval (30 days recommended); delegate read access for the LAPS password attribute to appropriate admin groups per tier; and configure audit logging on LAPS password retrievals. Windows LAPS (built into Windows 11 and Server 2025) extends the original LAPS with: Azure AD support, password encryption at rest in AD, automatic account management, and password history. LAPS is one of the highest-impact, lowest-cost controls for preventing ransomware lateral movement via Pass-the-Hash using local admin credentials."),
        ("Prevention Best Practices","qa",["email_macro_security","office_hardening"],P,"What Office macro security configurations effectively prevent macro-based ransomware delivery?","Microsoft Office macros remain a significant ransomware delivery vector despite declining prevalence. Key configurations: (1) Block macros in Office files from the internet: enable the GPO setting 'Block macros from running in Office files from the Internet' which blocks macros in files that have the Mark-of-the-Web (MOTW) attribute, meaning all downloaded files. (2) Disable VBA macros by default: set 'VBA Macro Notification Settings' to 'Disable all except digitally signed macros' requiring code signing for any macro execution. (3) Block Office from creating child processes: enable ASR rule D4F940AB-401B-4EFC-AADC-AD5F3C50688A to prevent Word, Excel, and other Office applications from launching cmd.exe, PowerShell, or other executables. (4) Block Win32 imports from Office macro code: enable ASR rule 92E97FA1-2EDF-4476-BDD6-9DD0B4DDDC7B. (5) Configure Trusted Locations for legitimate macro-enabled documents that are business-required. (6) Implement Azure Information Protection or Sensitivity Labels to control document macro execution based on sensitivity classification. Monitor for ASR rule triggers (Event ID 1121) to detect attempted macro exploitation."),
        ("Forensic Investigation","qa",["ransomware_process_tree","execution_analysis"],P,"How do you reconstruct the ransomware process execution tree from forensic evidence?","Process tree reconstruction reveals the complete execution chain from initial payload to encryption. Data sources: Event ID 4688 (Security log) records every process creation with the parent process ID, enabling tree construction; Sysmon Event ID 1 provides the same information plus command-line hashes and the parent command line. Tree construction: start from the ransomware process and trace backwards through parent PIDs to identify the complete chain: initial payload (e.g., macro document) spawning cmd.exe or PowerShell, downloading a secondary payload, which launches Cobalt Strike, which eventually deploys the ransomware binary. Tools: Event Log Explorer allows filtering by parent PID; Sysmon logs in Timeline Explorer enable sorting by ParentProcessId; and custom PowerShell scripts can automate tree construction from exported logs. Key analysis: identify privilege escalation points (where the process context changes from user to SYSTEM); identify injection points (where a legitimate process suddenly spawns suspicious children, indicating process injection by Cobalt Strike); and trace the deployment mechanism (the parent process of the ransomware on each encrypted system shows how it was distributed - via PsExec, WMI, scheduled task, or GPO). Present the process tree visually as a diagram showing the attack flow from initial compromise to encryption deployment."),
        ("Response Checklist","qa",["insurance_claims","cyber_insurance"],P,"How should organizations work with their cyber insurance carrier during a ransomware incident?","Cyber insurance coordination should begin immediately upon incident detection. Key steps: (1) Notify the carrier within the policy-specified timeframe (typically 24-72 hours) by contacting the claims hotline number listed in the policy. (2) The carrier will assign a breach coach (typically an attorney from a specialized law firm) who coordinates the response under attorney-client privilege. (3) The carrier may have pre-approved IR firms and negotiation firms; using their panel providers typically streamlines reimbursement. (4) Document all expenditures from the first hour: internal staff time, external consultant fees, hardware/software purchases, business interruption costs, and any overtime. (5) Maintain detailed records of: the incident timeline, all remediation actions, systems affected, data impacted, and recovery progress. (6) If considering ransom payment: the carrier's breach coach will coordinate OFAC compliance screening; some policies require carrier approval before payment; and the carrier may fund the payment directly. (7) For business interruption claims: maintain records of lost revenue, extra expenses, and the period of restoration. Common coverage areas: forensic investigation, legal counsel, breach notification, credit monitoring, ransom payment (if approved), business interruption, and regulatory defense costs."),
        ("Prevention Best Practices","qa",["threat_intelligence_program","proactive_defense"],P,"How should organizations use threat intelligence to proactively defend against ransomware?","A threat intelligence program for ransomware defense should include: strategic intelligence tracking which ransomware groups are currently most active, their targeting preferences, and emerging trends (sources: CISA advisories, vendor threat reports, ISAC bulletins); tactical intelligence monitoring IOCs from recent campaigns relevant to your industry (subscribe to CISA's automated indicator sharing, your ISAC feeds, and commercial TI platforms); and operational intelligence from monitoring dark web forums and Telegram channels for access broker listings mentioning your industry, geography, or revenue range. Actionable integration: feed IOCs into security tools (block malicious IPs/domains at firewall/proxy, deploy file hash detections to EDR, configure SIEM alerts for behavioral indicators); prioritize patching based on vulnerabilities being actively exploited by ransomware groups; adjust security controls based on the current threat landscape (e.g., if Akira is actively exploiting Cisco VPN, verify your VPN MFA enforcement); and conduct threat-informed purple team exercises emulating current top-group TTPs. Monitor ransomware leak sites for mentions of your organization, partners, and supply chain entities as early warning of potential compromise."),
        ("Forensic Investigation","qa",["malware_sandbox","dynamic_analysis"],P,"How should ransomware samples be safely analyzed in a sandbox environment?","Ransomware sandbox analysis requires careful isolation to prevent accidental damage. Environment setup: use a dedicated air-gapped hypervisor (not connected to production networks); create VM snapshots before executing malware; configure the VM with realistic but disposable data (test documents, fake databases) to trigger encryption behavior; and disable clipboard sharing, shared folders, and drag-and-drop between host and guest. Analysis workflow: (1) Static analysis first: examine the PE header, strings, imports, and resources without executing. (2) Configure monitoring tools: Process Monitor, Procmon, Wireshark (with INetSim or FakeNet-NG for network simulation), API Monitor, and Sysmon for detailed event logging. (3) Execute the sample and observe: files created/modified/deleted, registry changes, network connection attempts (C2 callbacks), process creation chains, and encryption behavior (speed, file type targeting, extension changes). (4) Capture the encrypted file samples for comparison with the original files (enables encryption mode identification). (5) Dump process memory during execution to extract the configuration and encryption keys. Public sandboxes: ANY.RUN provides interactive malware analysis; Joe Sandbox provides detailed behavioral reports; and Triage (Hatching) provides automated analysis with YARA rule matching. Never upload samples containing victim data to public sandboxes."),
        ("Prevention Best Practices","qa",["controlled_folder_access","windows_protection"],P,"How does Windows Controlled Folder Access protect against ransomware and what are its limitations?","Controlled Folder Access (CFA) is a Windows Defender feature that prevents unauthorized applications from modifying files in protected folders. Configuration: enable via GPO, Intune, or PowerShell (Set-MpPreference -EnableControlledFolderAccess Enabled); by default, it protects Documents, Pictures, Videos, Music, Desktop, and Favorites; additional folders can be added. When enabled: only applications on the Microsoft trusted list and administrator-specified allowlist can write to protected folders; unauthorized write attempts are blocked and logged (Event ID 1123 in Windows Defender Operational log). Limitations: CFA does not protect files outside the designated protected folders; it does not prevent encryption of files on network shares; ransomware running as SYSTEM may bypass CFA in some configurations; legitimate applications not on the trusted list will be blocked (requiring manual allowlisting, which creates an operational burden); and it does not protect against data exfiltration. Best practice: deploy CFA in audit mode first (Event ID 1124 for audit-only notifications) to identify legitimate applications that need allowlisting; then switch to enforcement mode after creating the necessary allowlist entries. CFA is a useful defense-in-depth layer but should not be relied upon as the sole ransomware protection."),
        ("Prevention Best Practices","qa",["microsoft_sentinel","cloud_siem"],P,"What Microsoft Sentinel analytics rules provide the best ransomware detection coverage?","Microsoft Sentinel provides built-in analytics rules and hunting queries for ransomware detection. Key built-in rules: 'Known ransomware file extension' detects mass file extension changes matching known ransomware patterns; 'Potential ransomware activity' detects patterns of file modification and process execution consistent with encryption; 'DEV-0270 indicators' and similar group-specific rules detect IOCs from MSTIC-tracked ransomware groups. Custom rules to implement: shadow copy deletion commands in process creation events (multiple command patterns for vssadmin, wmic, PowerShell); suspicious service installation from process creation data (Event ID 7045 correlation); credential dumping indicators from Defender for Identity or Sysmon LSASS access events; lateral movement patterns from SecurityEvent logon correlation (Type 3, 9, 10 across multiple systems); and bulk file modification detection using FileEvents or Sysmon Event ID 11. Hunting queries: use the built-in hunting notebooks for 'Ransomware' and 'Persistence' categories; create custom KQL queries for: encoded PowerShell execution across the fleet, Rclone command-line patterns, and authentication anomalies preceding ransomware deployment. Connect data sources: Microsoft 365 Defender, Azure AD, Sysmon, DNS, and firewall logs to enable cross-source correlation."),
    ]

    for s,e,t,p,q,a in data:
        m(s,e,t,p,q,a)
    return ex


def gen_kaspersky_batch3():
    S, U = "kaspersky_securelist", "https://securelist.com/modern-ransomware-groups-ttps/106824/"
    P, PI, PP = "kaspersky_qa_v3", "kaspersky_instruction_v3", "kaspersky_passage_v3"
    ex = []
    m = lambda s,e,t,p,q,a: ex.append(make_example(S,U,s,e,t,p,q,a))

    data = [
        ("Group TTPs","qa",["lockbit_builder","ransomware_tools"],P,"What happened when the LockBit 3.0 builder was leaked and how does it affect the threat landscape?","In September 2022, a disgruntled developer leaked the LockBit 3.0 builder, enabling anyone to generate custom LockBit 3.0 ransomware binaries without being an affiliate. This has significant implications: security teams now encounter LockBit 3.0 payloads deployed by groups with no affiliation to the actual LockBit RaaS, making attribution based on the ransomware payload unreliable; the leaked builder allows customization of encryption modes, file extensions, ransom note content, and process/service kill lists; low-skill attackers can create professional-grade ransomware without technical expertise; and incident responders must differentiate between official LockBit affiliate attacks and opportunistic users of the leaked builder. For investigation: check the watermark in the beacon configuration (official affiliates have unique watermarks); examine the overall sophistication of the intrusion TTPs (leaked builder users tend to have less sophisticated pre-encryption tradecraft); and compare the ransom note content against official LockBit templates. The leak also spawned derivative ransomware families that modified the builder code, creating new variants that share LockBit's encryption code but operate under different brands."),
        ("Group TTPs","qa",["medusa_ransomware","emerging_groups"],P,"Describe the Medusa ransomware group's TTPs and how they differ from other major groups.","Medusa (also known as MedusaLocker, though the two are distinct) emerged in 2023 as a significant ransomware operation. Initial access frequently exploits vulnerable internet-facing services, particularly Fortinet appliances, and uses compromised RDP credentials from brokers. Distinctive TTPs include: deployment of a web-based management shell for persistent access; use of PowerShell-based tooling for reconnaissance rather than compiled tools like AdFind; reliance on legitimate Windows tools (net commands, nltest, Advanced Port Scanner) rather than custom tooling; data exfiltration using custom PowerShell scripts rather than Rclone; and a distinctive negotiation approach using a public-facing leak blog alongside direct communication channels. The Medusa encryptor uses AES-256 encryption and appends the .MEDUSA extension. Forensic indicators include: the ransom note named '!!!READ_ME_MEDUSA!!!.txt'; evidence of web shell deployment (ASPX files in web-accessible directories); and PowerShell script artifacts in the attacker's working directory. Medusa's operators maintain regular working hours (UTC+3 timezone) and often exfiltrate data to a dedicated Medusa-controlled server rather than using commercial cloud storage."),
        ("Kill Chain","qa",["watering_hole","initial_access"],P,"How do ransomware groups use watering hole attacks for initial access and what investigation approach should be used?","Watering hole attacks involve compromising websites frequented by the target organization's employees. While less common than phishing for ransomware delivery, they have been observed in targeted campaigns. The attack flow: the attacker compromises a legitimate website relevant to the target industry (trade association, vendor portal, industry news site); they inject malicious code that selectively triggers for visitors from the target's IP range; the injected code exploits a browser or plugin vulnerability or delivers a trojanized download. Investigation approach: examine proxy logs for all users who visited the compromised website; identify which browser vulnerabilities were targeted by analyzing the injected code (if captured by proxy or IDS); check for evidence of drive-by download payloads in browser caches and download histories; look for exploit kit indicators in network traffic (redirects through multiple domains, obfuscated JavaScript); and examine the timeline of initial compromise against the website's compromised period. Key forensic artifacts: browser cache containing the malicious page, proxy logs showing the redirect chain, Event ID 4688 showing browser spawning unusual child processes, and Prefetch files for any downloaded payloads."),
        ("Group TTPs","qa",["bianlian","data_extortion"],P,"Describe the BianLian ransomware group's pivot from encryption to pure data extortion.","BianLian originally operated as a traditional double extortion group, encrypting victim data and threatening publication. In January 2023, Avast released a free decryptor for BianLian's Go-based encryptor, undermining their encryption-based business model. BianLian subsequently pivoted to pure data extortion: they infiltrate networks, exfiltrate sensitive data, and demand payment solely to prevent publication, without deploying any encryption payload. Their current TTPs include: initial access via exploited ProxyShell vulnerabilities or compromised VPN/RDP credentials; deployment of custom backdoors written in Go; use of Rclone and MEGA for data exfiltration; and lateral movement using PsExec and RDP. The absence of encryption makes detection harder since there are no encrypted files or ransom notes to trigger incident response. Detection relies on: identifying unusual data exfiltration patterns, monitoring for BianLian's custom Go backdoors (identifiable by Go runtime artifacts), and receiving notification from the threat actor themselves or from law enforcement. The FBI/CISA advisory AA23-136A provides comprehensive IOCs for BianLian."),
        ("MITRE ATT&CK","qa",["t1059","command_scripting"],P,"How do different ransomware groups abuse command and scripting interpreters (T1059) and what variations exist?","T1059 abuse varies by group sophistication and preference. PowerShell (T1059.001): the most commonly abused interpreter; Conti operators used PowerShell for downloading Cobalt Strike beacons and AD reconnaissance; LockBit affiliates use PowerShell for disabling Windows Defender; and BlackCat's affiliates use PowerShell for automated credential harvesting. Detection: Script Block Logging (Event ID 4104) captures full deobfuscated content. Windows Command Shell (T1059.003): used by all groups for basic operations (net commands, taskkill, sc, bcdedit); batch scripts are common for automating pre-encryption steps (shadow copy deletion, service stopping). Python (T1059.006): increasingly used by groups like BlackCat for custom tooling and automation; Python scripts for data collection and exfiltration leave .py files and Python runtime artifacts. VBScript/JavaScript (T1059.005/007): used in initial access via malicious documents and HTA files; detection through process creation logs showing wscript.exe or cscript.exe execution from user-writable directories. Unix Shell (T1059.004): used on Linux/ESXi targets for VM shutdown, encryption execution, and persistence via cron. Each interpreter leaves distinct forensic artifacts; comprehensive logging across all interpreters is essential for complete attack reconstruction."),
        ("Defensive Recommendations","qa",["micro_segmentation","network_security"],P,"How does micro-segmentation prevent ransomware lateral movement in modern enterprise networks?","Micro-segmentation applies granular network access controls at the workload level, going beyond traditional VLAN-based segmentation. Implementation approaches: software-defined networking (SDN) policies that define allowed communication paths between specific applications and services; host-based firewall rules (Windows Firewall, iptables) managed centrally via policy engines; and identity-based access controls that verify both the user and device before allowing any network connection. For ransomware prevention: each workload communicates only with its explicitly authorized dependencies, so even if an attacker compromises a web server, they cannot reach the database server on a different segment without a specific policy allowing it. Key policies: workstation-to-workstation: deny all (prevents SMB-based ransomware propagation); workstation-to-server: allow only specific application ports (HTTP/S to web servers, SMB to designated file servers); server-to-server: allow only documented application dependencies; and management access: restricted to jump servers with MFA. Implementation phases: (1) discovery and mapping of existing traffic flows; (2) policy definition based on discovered flows plus security requirements; (3) monitoring mode to verify policies do not break legitimate traffic; (4) enforcement mode with alerting on policy violations. Tools: Illumio, Guardicore (Akamai), VMware NSX, and Cisco ACI."),
        ("Group TTPs","qa",["rhysida_ransomware","emerging_threats"],P,"Describe the Rhysida ransomware group's targeting patterns and technical capabilities.","Rhysida emerged in May 2023 and rapidly became notable for targeting healthcare, education, and government sectors. Their TTPs include: initial access through phishing emails or exploitation of internet-facing services; deployment of Cobalt Strike for C2; use of PsExec for lateral movement; and custom PowerShell scripts for network reconnaissance. The Rhysida encryptor uses ChaCha20 for file encryption and RSA-4096 for key encryption, appending the .rhysida extension. Distinctive characteristics: Rhysida operators claim to be a 'cybersecurity team' helping organizations identify vulnerabilities, framing the ransom payment as a 'fee for services'; they use a professional-looking leak site with a search function; and they have targeted high-profile victims including the British Library and healthcare systems. A cryptographic weakness in Rhysida's implementation was discovered by Korean researchers (KISA) in early 2024, enabling a decryptor that works by recovering the internal CSPRNG state used for key generation. This decryptor works for early Rhysida versions but was patched in later variants. The CISA advisory AA23-319A provides detailed IOCs and TTPs."),
        ("Kill Chain","qa",["credential_stuffing","initial_access"],P,"How do ransomware groups use credential stuffing attacks and what forensic indicators help identify them?","Credential stuffing uses credentials leaked from previous data breaches to authenticate against target services. Ransomware groups obtain credential lists from: underground forums selling breach databases, infostealer malware logs (Raccoon, Vidar, RedLine) that capture browser-stored credentials, and aggregated credential databases. Targeted services include: VPN portals, RDP gateways, email (OWA, M365), and web applications. Forensic indicators: high volumes of failed authentication attempts (Event ID 4625) from multiple source IPs against multiple accounts (distributed credential stuffing); successful authentication using credentials that match known breached credentials; authentication from VPN/proxy IP addresses or TOR exit nodes; login attempts for accounts that have been dormant; and geographic anomalies in authentication source locations. Investigation: check authentication logs for the pattern of failed-then-successful logins; correlate successful authentication source IPs against threat intelligence feeds; verify whether affected accounts used passwords known to be in breach databases using tools like Have I Been Pwned's API; and trace post-authentication activity to determine what the attacker did after gaining access. Prevention: enforce unique passwords using breach detection integration, mandatory MFA, and account lockout policies with progressive delays."),
        ("Group TTPs","qa",["scattered_spider","social_engineering"],P,"How does the Scattered Spider threat group combine social engineering with ransomware deployment?","Scattered Spider (also tracked as UNC3944, 0ktapus) represents a new generation of ransomware operators who rely heavily on social engineering rather than technical exploitation. Their TTPs include: calling IT help desks while impersonating employees to request password resets and MFA enrollment; SIM swapping to intercept SMS-based MFA codes; phishing targeting Okta and other identity providers to steal session tokens; and using social engineering to enroll attacker-controlled devices in MFA. Once inside, they demonstrate strong technical skills: compromising cloud identity infrastructure (Okta, Azure AD), deploying commercial RMM tools for persistence, using cloud-native management tools for lateral movement within Azure/M365, and deploying ALPHV/BlackCat ransomware. Investigation unique aspects: check identity provider logs (Okta system log, Azure AD) for MFA enrollment changes, password resets from unusual sources, and session token generation; review help desk ticket systems for social engineering calls; check mobile carrier records for SIM swap events; and examine cloud management audit logs. Detection: implement out-of-band verification for all password reset and MFA enrollment requests; alert on MFA method changes; and implement behavioral analytics on identity provider authentication patterns."),
        ("Cross-Group Analysis","passage",["ransomware_2025","threat_evolution"],PP,"Describe the key ransomware threat landscape trends visible in 2025.","The 2025 ransomware landscape reflects several significant trends. Post-disruption adaptation: following Operation Cronos against LockBit and the ALPHV/BlackCat exit scam, the ecosystem fragmented with affiliates migrating to newer platforms (RansomHub, Akira, Play, Medusa) and some forming new, smaller groups. Pure data extortion growth: groups like Clop and BianLian have demonstrated that encryption is optional when stolen data provides sufficient leverage, reducing operational risk for the attacker. Edge device exploitation: exploitation of VPN appliances (Ivanti, Fortinet, Palo Alto), firewalls, and managed file transfer solutions displaced phishing as the primary initial access vector for sophisticated groups. AI-assisted operations: threat actors use AI for crafting more convincing phishing emails, automating reconnaissance, and developing evasion techniques, though the core TTPs remain recognizable. Cloud targeting maturity: attacks increasingly target cloud identity infrastructure, cloud-native services, and SaaS platforms rather than focusing solely on on-premises Active Directory. Healthcare and critical infrastructure: continued targeting of sectors with high urgency to restore operations, leveraging life-safety implications for payment pressure. The defensive response has also evolved: immutable backups becoming standard, EDR adoption nearing ubiquity in enterprise environments, and law enforcement disruption operations becoming more frequent and coordinated internationally."),
        ("Defensive Recommendations","passage",["security_architecture","defense_strategy"],PP,"Describe a modern security architecture designed to be resilient against ransomware attacks.","A ransomware-resilient architecture integrates prevention, detection, and recovery capabilities. Identity layer: implement Zero Trust with phishing-resistant MFA on all access paths; deploy Privileged Access Management with just-in-time elevation; implement tiered administration with PAWs for Tier 0 management; and monitor all authentication with UEBA for anomaly detection. Network layer: micro-segment the network with default-deny policies between workload tiers; implement DNS security with protective DNS services; deploy network detection and response (NDR) for encrypted traffic analysis; and maintain separate management networks for backup and security infrastructure. Endpoint layer: deploy EDR with tamper protection on all systems; implement application allowlisting on high-value systems; enable attack surface reduction rules and Controlled Folder Access; and maintain Sysmon with comprehensive configuration forwarded to SIEM. Data layer: implement the 3-2-1-1 backup rule (three copies, two media types, one offsite, one immutable); deploy DLP for exfiltration detection; encrypt sensitive data at rest; and implement cloud storage immutability. Detection layer: centralize logs in SIEM with 90+ day retention; implement automated detection for ransomware kill chain phases; maintain 24/7 SOC coverage; and conduct quarterly purple team exercises. Recovery layer: tested restoration procedures with documented RTOs/RPOs; pre-positioned IR retainer; and annual ransomware tabletop exercises."),
        ("Kill Chain","qa",["dll_sideloading","defense_evasion"],P,"How do ransomware operators use DLL side-loading for defense evasion and what forensic artifacts result?","DLL side-loading exploits the Windows DLL search order to load a malicious DLL using a legitimate application. The attacker places a malicious DLL alongside a legitimate, signed executable that loads DLLs from its current directory before checking system directories. Common abused applications: legitimate signed antivirus executables (the irony of using AV software to load malware), OneDrive updater, legitimate Microsoft binaries, and various software installers. Forensic artifacts: Sysmon Event ID 7 (ImageLoaded) showing a DLL loaded from an unusual directory (the attacker's working directory rather than System32); the legitimate executable running from a non-standard path (C:\\ProgramData\\, C:\\Users\\Public\\, temp directories); process creation (Event ID 4688/Sysmon Event ID 1) showing the legitimate executable launched from an unusual location; and the malicious DLL file on disk (often with the same name as a legitimate system DLL). Detection: baseline DLL loading patterns for commonly side-loaded applications; alert on signed executables running from non-standard directories; and use Sysmon Event ID 7 with hash validation to detect DLLs that do not match known-good versions."),
        ("Kill Chain","qa",["ntds_dit_theft","credential_access"],P,"How do ransomware operators extract the NTDS.dit file and what detection strategies exist?","NTDS.dit is the Active Directory database file (C:\\Windows\\NTDS\\ntds.dit on domain controllers) containing all domain password hashes. Extraction techniques: ntdsutil.exe 'activate instance ntds' 'ifm' 'create full c:\\temp' 'q' 'q' (creates an Install From Media copy including NTDS.dit and registry hives); Volume Shadow Copy: vssadmin create shadow /for=C: followed by copy of NTDS.dit from the shadow copy path; and direct disk access using tools like NinjaCopy or raw NTFS reading. Detection: Event ID 4688 showing ntdsutil.exe execution with IFM-related arguments; Event ID 8222 (shadow copy creation) followed by file access to the shadow copy NTDS.dit path; Sysmon Event ID 11 (FileCreate) showing NTDS.dit copied to a non-standard directory; and Event ID 4663 (file access audit) on the original NTDS.dit file from non-SYSTEM processes. Prevention: restrict interactive logon to domain controllers to only authorized Tier 0 accounts; implement Windows Defender Credential Guard on DCs; monitor for volume shadow copy creation on DCs; and alert on any ntdsutil.exe execution. If NTDS.dit extraction is confirmed, assume all domain credentials are compromised and plan for full password reset of all accounts."),
        ("Group TTPs","qa",["hunters_international","group_analysis"],P,"Describe the Hunters International ransomware group and their relationship to Hive.","Hunters International emerged in October 2023, shortly after the FBI's takedown of Hive infrastructure. Analysis of the Hunters International encryptor revealed significant code overlap with Hive ransomware (over 60% code similarity), leading researchers to assess it as either former Hive developers or a group that acquired Hive's source code. Hunters International's operators initially denied the connection, claiming they purchased the code. Their TTPs include: initial access via exploited Citrix and Fortinet vulnerabilities and compromised RDP; deployment of Cobalt Strike and SystemBC for C2 and tunneling; use of Mimikatz for credential harvesting; and data exfiltration before encryption. The encryptor appends a .locked extension and drops a 'Contact Us.txt' ransom note directing victims to a Tor-based negotiation site. Distinctive characteristics: Hunters International claimed to prioritize data theft over encryption (though they still encrypt), suggesting a shift toward data extortion; they target a wide range of industries globally; and their leak site organizes stolen data by category for maximum exposure. For investigation, check for Hive-related IOCs alongside Hunters International-specific indicators, as the shared codebase means some detection rules for Hive may trigger on Hunters International samples."),
        ("Defensive Recommendations","qa",["security_awareness","human_factor"],P,"What security awareness training topics are most effective at preventing ransomware-related social engineering?","Effective ransomware-focused security awareness training should cover: phishing recognition specific to current delivery methods (HTML smuggling, QR code phishing, callback phishing/BazarCall, thread hijacking), not just generic phishing awareness; the importance of reporting suspicious emails rather than just deleting them (one report can prevent organization-wide compromise); MFA fatigue awareness training explaining that legitimate MFA prompts only appear when the user is actively logging in, and unexpected prompts should be reported immediately; USB security awareness for environments where USB-based attacks are a risk; the concept of pretexting and voice phishing (vishing) where attackers call pretending to be IT support requesting credentials or remote access; safe handling of password-protected attachments (legitimate senders rarely send password-protected ZIPs unless pre-arranged); browser download safety focusing on the risks of SEO poisoning (Gootloader) where search results lead to malicious downloads; and the principle that IT staff will never ask for passwords over the phone or via email. Training should be reinforced with regular simulated phishing exercises, with results used for targeted retraining rather than punishment."),
    ]

    for s,e,t,p,q,a in data:
        m(s,e,t,p,q,a)
    return ex


def gen_dfir_batch3():
    S, U = "dfir_report", "https://thedfirreport.com/"
    P, PI, PP = "dfir_qa_v3", "dfir_instruction_v3", "dfir_passage_v3"
    ex = []
    m = lambda s,e,t,p,q,a: ex.append(make_example(S,U,s,e,t,p,q,a))

    data = [
        ("Intrusion Investigation","instruction",["systembc_proxy","c2_tunneling"],PI,"How should investigators analyze SystemBC proxy tool usage during ransomware investigations?","SystemBC is a proxy/tunnel malware used by multiple ransomware groups (Conti, Ryuk, Egregor, DarkSide, Black Basta) for maintaining covert C2 channels. Investigation approach: identify the SystemBC DLL or executable on disk (typically dropped in %TEMP% or %APPDATA%); it installs as a Windows service (Event ID 7045) with a random name; examine the binary's embedded configuration to extract: SOCKS5 proxy port, C2 server addresses, and communication encryption keys. Network indicators: SystemBC creates a SOCKS5 proxy on the infected host (commonly ports 1080 or 4001-4999); it establishes encrypted connections to the C2 server using a custom protocol; and it may use Tor for C2 communication (check for connections to Tor guard nodes). Forensic artifacts: service installation events, process creation logs showing the SystemBC binary, network connections from the SystemBC process to external servers, and registry keys for service persistence. SystemBC's proxy functionality allows the attacker to tunnel other tools (Cobalt Strike, Mimikatz, PsExec traffic) through the infected host, so investigate all traffic flowing through the SystemBC proxy to understand the full scope of attacker activity."),
        ("Intrusion Investigation","instruction",["threema_c2","encrypted_c2"],PI,"Describe how to investigate ransomware intrusions that use legitimate messaging services for C2 communication.","Some ransomware operators abuse legitimate services (Slack, Discord, Telegram, Microsoft Teams) for C2 communication to blend with normal enterprise traffic. Investigation approach: identify the specific service being abused by examining: outbound connections from non-standard processes to messaging service APIs (e.g., discord.com/api/webhooks, api.telegram.org/bot); unusual process trees where attack tools communicate via HTTP to these services; and DNS queries to messaging service domains from processes that should not be communicating with them. Evidence collection: proxy logs showing API calls to messaging services from compromised systems; the HTTP request bodies may contain encoded commands (POST to webhook URLs with data payloads); and the response bodies may contain instructions from the attacker. For Discord: webhook URLs contain a channel-specific token that can be revoked if reported to Discord's Trust & Safety team; examine the webhook URL for channel and token information. For Telegram: bot API tokens in the malware configuration can be used to query the bot's message history if obtained early enough. Detection: monitor for API calls to messaging platforms from non-browser processes; alert on messaging service connections from server-class systems; and implement DNS-level monitoring for messaging service domains from systems that should not access them."),
        ("Kill Chain Analysis","passage",["attack_timing","operational_patterns"],PP,"Describe the timing patterns DFIR Report cases reveal about ransomware operator behavior during the work week.","DFIR Report timeline analysis across hundreds of intrusions reveals consistent timing patterns. Initial access: phishing emails are typically sent during the target's business hours (maximizing the chance of interaction), while exploitation of vulnerabilities occurs at any time (often automated). Operator engagement: manual post-exploitation typically begins during the operator's business hours (commonly UTC+3 to UTC+5, correlating with Eastern European time zones), usually 2-8 hours after initial access. Reconnaissance and lateral movement: operators work in focused sessions of 4-8 hours, similar to a normal work day, with activity gaps corresponding to sleep periods. Exfiltration: data exfiltration often occurs during the victim's off-hours (evenings and weekends) when network monitoring may be less closely watched and outbound traffic anomalies are less likely to be noticed. Ransomware deployment: detonation frequently occurs on Friday evening or Saturday morning in the victim's time zone, maximizing the time before IT staff are available to respond. Some groups deploy on Sunday night to disrupt Monday morning operations. Understanding these patterns helps: SOC teams allocate resources (increased monitoring during off-hours), incident responders predict attacker next steps based on the current phase and time of day, and threat hunters focus their searches during the predicted active periods."),
        ("Forensic Analysis","qa",["process_injection_detection","advanced_techniques"],P,"What process injection techniques do ransomware operators use and how do you detect each one?","Process injection techniques and their detection artifacts: (1) CreateRemoteThread injection: Sysmon Event ID 8 (CreateRemoteThread) showing the source (attacker) and target (victim) processes; commonly used by Cobalt Strike's default inject mechanism. (2) Process hollowing: the target process is created in a suspended state, its memory is unmapped and replaced with malicious code, then resumed; detectable via Sysmon Event ID 1 showing a suspended process, followed by Event ID 10 (ProcessAccess) with WriteProcessMemory access rights, then the process resuming with unexpected behavior. (3) APC injection (QueueUserAPC): queues an asynchronous procedure call in a target thread; harder to detect but visible through Sysmon Event ID 10 with specific access masks. (4) DLL injection via LoadLibrary: forces a target process to load a malicious DLL; Sysmon Event ID 7 shows the unexpected DLL loaded into the target process. (5) Reflective DLL injection: loads a DLL from memory without touching disk; no file-based artifacts, but Event ID 10 (ProcessAccess) from the injecting process targeting the victim process is visible. (6) Module stomping: overwrites the memory of a legitimately loaded DLL with malicious code; detectable by comparing in-memory DLL content against the on-disk file. For all techniques: compare process behavior (network connections, file access) against its expected behavior baseline."),
        ("Forensic Analysis","qa",["edr_bypass_detection","security_evasion"],P,"What artifacts indicate that an attacker has successfully bypassed or disabled EDR during a ransomware attack?","EDR bypass leaves several artifact categories. Service/process termination: Event ID 7036 showing the EDR service entering a stopped state; Event ID 4689 or Sysmon Event ID 5 showing the EDR process terminating unexpectedly; and gaps in EDR telemetry visible in the management console (the agent going offline without a corresponding system shutdown). BYOVD artifacts: Event ID 7045 showing a vulnerable driver service installation; the vulnerable driver file on disk; and the EDR killer tool in the attacker's working directory. Configuration tampering: registry modifications to EDR-related keys disabling real-time protection or specific detection features; Group Policy modifications disabling EDR via domain-level policy; and Windows Defender-specific events (Event ID 5001 - real-time protection disabled, 5007 - configuration changed). AMSI bypass: PowerShell Script Block Logging may capture AMSI bypass techniques (amsiInitFailed, reflection-based patching); and anomalous PowerShell execution without corresponding AMSI scan events. Safe Mode abuse: bcdedit commands enabling Safe Mode with networking; and system boot into Safe Mode where EDR services do not start. Detection of EDR bypass itself should be a critical alert, as it almost certainly precedes ransomware deployment. Monitor EDR agent health centrally and alert immediately when any agent goes offline unexpectedly."),
        ("Forensic Analysis","qa",["virtual_machine_forensics","vm_investigation"],P,"What unique forensic considerations apply when investigating ransomware on virtual machines?","VM-based investigation has unique aspects. VM snapshot forensics: VMware snapshots (.vmem, .vmsn) contain the VM's memory state at snapshot creation; these are analyzable with Volatility as memory dumps, potentially preserving encryption keys and running processes from before the ransomware executed. VMDK analysis: forensic imaging of VMDK files can be done using FTK Imager or converting VMDK to raw format using qemu-img convert; flat VMDKs can be mounted directly as forensic images. Hypervisor logs: VMware vCenter maintains logs of VM operations (power on/off, snapshot creation/deletion, vMotion, resource changes) that may show the attacker shutting down VMs before ESXi encryption; ESXi host logs (/var/log/hostd.log, /var/log/vmkernel.log) record management operations. VM-specific attack artifacts: ransomware targeting ESXi modifies or encrypts .vmdk, .vmem, .vswp, .vmx, and .nvram files; some variants only encrypt the VMDK descriptor (small file) rather than the flat VMDK data file, enabling recovery by recreating the descriptor. Thin provisioning: thin-provisioned VMDKs may have recoverable data in unallocated areas of the VMFS datastore. Recovery consideration: VMware has documented procedures for recreating VMDK descriptors that can restore access to VMs where only the descriptor was encrypted."),
        ("Intrusion Investigation","instruction",["multi_ransomware","complex_intrusions"],PI,"How should investigators handle cases where multiple ransomware groups have access to the same environment simultaneously?","Multiple concurrent threat actors (a scenario more common than expected) require careful investigation methodology. Identification: differentiate threat actors by: the tools and TTPs they use (one operator using Cobalt Strike while another uses Sliver); separate C2 infrastructure (different C2 servers for different operators); different working hours and activity patterns; and distinct persistence mechanisms on different systems. Common scenarios: an access broker sells access to multiple buyers; two affiliates of different RaaS platforms have independent access; or an initial attacker is still present when a second gains entry through a different vector. Investigation approach: build separate timelines for each threat actor, using tool-specific artifacts as discriminators; track each actor's lateral movement path independently; identify whether the actors are aware of each other (evidence of one cleaning up the other's tools or competing for resources); and assess whether both actors exfiltrated data (potentially increasing the breach scope). Remediation: ensure eradication addresses ALL threat actors' persistence mechanisms, not just the more visible one. The presence of one ransomware group should trigger a thorough search for additional compromise, as the same vulnerabilities that admitted one group may have been exploited by others."),
        ("Forensic Analysis","qa",["macro_analysis","document_forensics"],P,"How do you analyze a malicious Office document that was used to deliver ransomware?","Malicious Office document analysis follows a structured approach. Static analysis: use olevba (oletools) to extract VBA macros from .doc/.docm files; examine macro code for: auto-execution triggers (AutoOpen, Document_Open, Workbook_Open), obfuscation techniques (character code concatenation, base64 encoding, environment variable abuse), external calls (Shell, WScript.Shell, PowerShell invocations, WMI calls), and URLs for payload download. For OOXML formats (.docx, .xlsx): unzip the file and examine relationships (word/_rels/document.xml.rels) for external template references (template injection attacks); check embedded objects and OLE packages. Dynamic analysis: execute in a sandboxed environment with network simulation; capture the full process chain from the Office application through payload delivery. Specific checks: look for DDE (Dynamic Data Exchange) payloads in field codes; examine embedded macros for Cobalt Strike shellcode; check for ActiveX control abuse; and identify VBA stomping (where the compiled p-code differs from the visible VBA source). Tools: oletools suite (olevba, oledump, rtfdump), ViperMonkey for VBA emulation, and YARA rules targeting known macro patterns. Document the complete execution chain: document opens, macro triggers, command executed, payload downloaded, and secondary execution, providing the full initial access narrative."),
        ("Kill Chain Analysis","passage",["post_exploitation_timing","operational_tempo"],PP,"Describe the typical operational tempo DFIR Report cases document from initial beacon to ransomware deployment.","Operational tempo varies significantly by operator skill and objective but follows recognizable patterns. Fast operators (24-48 hours): typically LockBit affiliates who buy access from brokers, perform minimal reconnaissance (nltest, net group commands), quickly locate and compromise domain admin credentials using Mimikatz, skip data exfiltration entirely, and deploy ransomware via PsExec or the LockBit auto-spreading feature. These fast attacks show lower total impact (often missing backup destruction and cloud resources) but are harder to intercept. Methodical operators (7-14 days): follow a structured playbook with distinct phases; days 1-2 for reconnaissance using BloodHound and manual enumeration; days 2-4 for credential harvesting and privilege escalation via multiple techniques; days 4-7 for extensive lateral movement establishing access to all critical systems; days 5-10 for data identification, staging, and exfiltration to cloud storage; and days 10-14 for pre-encryption preparation and synchronized deployment. Extended operations (30+ days): APT-linked ransomware groups or groups targeting large enterprises may maintain access for months, maximizing data theft and developing deep understanding of the victim's network for maximum impact. Each tempo pattern has different detection windows and requires different response urgency."),
        ("Forensic Analysis","qa",["network_share_forensics","smb_analysis"],P,"How do you forensically analyze SMB network share access patterns during a ransomware investigation?","SMB share access forensics combines multiple evidence sources for comprehensive analysis. On the file server: Event ID 5140 (network share accessed) records: the share name, source IP address, and account used for each share connection. Event ID 5145 (detailed file share access) records individual file operations: file path, access type (ReadData, WriteData, Delete, ReadAttributes), source IP, and account, providing granular evidence of which files the attacker accessed and modified. Windows Firewall logs on the server record inbound SMB connections. On the client (attacker's system): MountPoints2 registry key records mapped network shares; LNK files in Recent Items contain UNC paths to files accessed on shares; and ShellBags record directory browsing on network paths. Network evidence: NetFlow or firewall logs showing SMB (TCP 445) connections between specific source and destination systems; high-bandwidth SMB sessions indicating mass file access or encryption; and unusual SMB connection patterns (workstation-to-workstation, or a single system connecting to many file servers rapidly). For ransomware encryption scope: analyze Event ID 5145 write events to identify all files encrypted via SMB, building a comprehensive list of affected files across all network shares."),
        ("Intrusion Investigation","instruction",["iso_lnk_delivery","initial_access"],PI,"Describe how to investigate an ISO/LNK file delivery chain commonly used for ransomware initial access.","ISO/LNK delivery chains became dominant after Microsoft disabled Office macros by default. The attack flow: a phishing email contains a link to download or directly attaches an ISO (or IMG) file. When opened, Windows mounts the ISO as a virtual drive, and the contents do not carry the Mark-of-the-Web (MOTW) attribute, bypassing SmartScreen and macro restrictions. The ISO typically contains: a visible LNK (shortcut) file disguised as a document (using a PDF or document icon); and a hidden folder containing a DLL payload. The LNK executes: rundll32.exe hidden_folder\\payload.dll,DllMain or a similar command. Investigation: check email logs for the ISO file delivery; examine the user's Downloads folder and Recycle Bin for the ISO file; check for ISO mount events (Event ID 12 in System log or MountedDevices registry); parse the LNK file using LECmd to extract the embedded command showing the DLL execution path; examine Prefetch for rundll32.exe and the target DLL; and check Sysmon Event ID 1 for the process chain from explorer.exe opening the LNK to rundll32.exe loading the DLL. The DLL payload (typically IcedID, QakBot, or BumbleBee) then establishes C2 and begins the post-exploitation phase."),
        ("Forensic Analysis","qa",["bootkit_detection","firmware_analysis"],P,"How do you detect MBR/VBR modification by destructive ransomware variants?","Some ransomware variants modify the Master Boot Record (MBR) or Volume Boot Record (VBR) instead of or in addition to file encryption. Notable examples: Petya/GoldenEye replaced the MBR with a custom boot loader that displayed a ransom note and encrypted the Master File Table; NotPetya used the same MBR replacement but was actually a wiper disguised as ransomware; and some ransomware variants modify the boot configuration to prevent recovery mode access. Detection: compare the first 512 bytes of the physical disk (sector 0, the MBR) against known-good MBR code; on UEFI systems, examine the EFI System Partition for modified bootloaders; check bcdedit output for modified boot configuration entries; and monitor for disk access events at the raw sector level (some EDR tools can detect raw disk writes to the boot sector). Forensic analysis: use a hex editor to examine sector 0 for non-standard boot code; check for the Windows boot signature (0x55AA) at offset 510-511; compare the partition table against expected values; and on UEFI systems, examine the BCD (Boot Configuration Data) store for unauthorized entries. Recovery from MBR modification: the Windows Recovery Environment can rebuild the MBR (bootrec /fixmbr, bootrec /fixboot); for data recovery, mount the affected disk as a secondary drive and access the NTFS partitions directly."),
        ("Forensic Analysis","qa",["encrypted_traffic_analysis","tls_inspection"],P,"How can encrypted network traffic be analyzed during ransomware investigations without TLS inspection?","When TLS inspection is not available, encrypted traffic analysis relies on metadata and behavioral patterns. JA3/JA3S fingerprinting: the TLS client hello and server hello messages are unencrypted and contain unique fingerprints based on cipher suites, extensions, and elliptic curves; Cobalt Strike, Brute Ratel, and other C2 tools have distinctive JA3 fingerprints identifiable in network captures. JARM fingerprinting: active TLS fingerprinting that identifies the server-side TLS implementation; Cobalt Strike team servers have known JARM signatures. Traffic pattern analysis: beacon intervals identifiable through connection timing analysis even in encrypted sessions; data volume patterns showing consistent small check-ins punctuated by larger data transfers (tasking responses); and session duration patterns. Certificate analysis: examine TLS certificates for: self-signed certificates (common in quick-deploy C2), certificates from free providers (Let's Encrypt) on unusual domains, certificate validity periods and subject names that do not match the apparent service, and certificates with anomalous issuer chains. DNS correlation: match encrypted connection destinations with DNS queries to identify the domains being accessed. Flow analysis: NetFlow data reveals connection patterns, byte counts, and durations without requiring decryption."),
    ]

    for s,e,t,p,q,a in data:
        m(s,e,t,p,q,a)
    return ex


def gen_sans_batch3():
    S, U = "sans_dfir", "https://www.sans.org/posters/dfir-cheatsheet-booklet/"
    P, PI, PP = "sans_qa_v3", "sans_instruction_v3", "sans_passage_v3"
    ex = []
    m = lambda s,e,t,p,q,a: ex.append(make_example(S,U,s,e,t,p,q,a))

    data = [
        ("Evidence Collection","qa",["forensic_image_formats","acquisition"],P,"What are the differences between forensic image formats (E01, AFF4, raw/dd) and when should each be used?","Forensic image formats serve different purposes. E01 (EnCase Evidence File): the most widely used forensic format; supports compression (reducing storage by 30-60%), built-in MD5/SHA1 verification, case metadata embedding, and segmented file output (e.g., 2GB segments for FAT32 compatibility). Recommended for: most investigations, long-term evidence storage, and when court-admissible evidence is required. Raw/dd: a bit-for-bit copy of the source media with no overhead or metadata; universally compatible with all forensic tools; but no built-in integrity verification (must compute and record hashes separately) and no compression. Recommended for: maximum compatibility, when mounting the image directly is needed, and when processing speed is critical. AFF4 (Advanced Forensic Format 4): a modern format supporting arbitrary metadata, compression, encryption, and deduplication; faster acquisition than E01; but limited tool support compared to E01. Recommended for: high-speed acquisition of large storage arrays, and environments already using AFF4-compatible tools. For ransomware investigations: use E01 for formal evidence (systems in the attack path, patient zero, domain controllers) and raw format for rapid triage imaging when speed is critical. Always compute SHA256 hashes regardless of format."),
        ("Forensic Analysis","qa",["memprocfs","memory_analysis"],P,"How does MemProcFS enable efficient memory forensic analysis during ransomware investigations?","MemProcFS is a memory forensics tool that presents memory dumps as a virtual file system, enabling analysis using standard file browsing tools rather than specialized memory commands. Key capabilities: it mounts a memory dump as a drive letter containing a virtual directory structure with: /proc/ showing all processes with their modules, handles, threads, and memory maps; /forensic/ providing parsed forensic artifacts (timeline, registry, network connections); /sys/ showing system information (certificates, services, modules). For ransomware investigation advantages: analysts can browse process memory using standard file tools; extract files from process memory spaces using copy operations; view parsed registry hives from memory without separate tools; access network connection data in a structured format; and perform all operations at analysis speed rather than waiting for Volatility plugin execution. Integration: MemProcFS supports Python plugins for custom analysis; it can analyze live memory (via FPGA-based DMA), hibernation files, and standard memory dumps; and its output can be piped to other tools for automated processing. Practical workflow: mount the memory dump, browse to /proc/<pid>/modules/ to examine the ransomware process, copy the process's memory sections to disk for malware analysis, check /forensic/ntfs/ for cached file system data, and review /sys/net/ for C2 connections."),
        ("Forensic Analysis","qa",["windows_defender_quarantine","malware_recovery"],P,"How do you recover malware samples from Windows Defender quarantine for analysis during ransomware investigations?","Windows Defender quarantine stores detected malware in an encrypted format at C:\\ProgramData\\Microsoft\\Windows Defender\\Quarantine\\. Recovery methods: (1) Using MpCmdRun.exe: 'MpCmdRun.exe -Restore -ListAll' shows quarantined items; 'MpCmdRun.exe -Restore -Name <threat_name> -Path <output_directory>' restores a specific item. (2) Direct quarantine extraction: quarantine files are stored with a .D extension in timestamped subdirectories; tools like Defender quarantine extractor can decrypt and extract the original malware sample. (3) From the Defender event log: Event ID 1116 records the original file path and threat name, enabling correlation with quarantine entries. Forensic value: quarantined samples may include: the initial malware payload detected before the attacker disabled Defender; reconnaissance tools or credential harvesters that were detected and quarantined while the attacker continued with other tools; and samples from earlier in the attack timeline that provide the earliest evidence of compromise. Important: recovering samples from quarantine requires administrative access; handle recovered malware with appropriate safety precautions (dedicated analysis VM); and document the recovery in the chain of custody, noting the quarantine date, original path, and threat name as identified by Defender."),
        ("Forensic Analysis","qa",["sigma_rule_creation","detection_engineering"],P,"How do you write custom SIGMA rules for detecting ransomware-specific TTPs?","SIGMA rules provide vendor-agnostic detection logic that can be converted to SIEM-specific queries. Structure: a SIGMA rule contains: title and description, log source specification (product, service, category), detection logic (selection and condition), false positive notes, severity level, and MITRE ATT&CK tags. Example for shadow copy deletion: title: 'Shadow Copy Deletion via Vssadmin'; logsource: product: windows, category: process_creation; detection: selection with CommandLine containing 'vssadmin' and 'delete' and 'shadows'; level: critical; tags: attack.impact, attack.t1490. Best practices: write rules targeting specific command-line patterns rather than just process names (reduces false positives); use the 'near' modifier for correlated events (shadow copy deletion followed by backup catalog deletion within 60 seconds); include multiple selection alternatives for the same TTP (vssadmin, wmic, PowerShell methods for shadow copy deletion); test rules against both malicious samples and benign baseline data to verify true positive and false positive rates; and use severity levels appropriately (critical for imminent-threat indicators like shadow copy deletion, high for credential theft, medium for reconnaissance). Convert SIGMA rules to your SIEM format using sigma-cli or pySigma. Share rules through the SigmaHQ GitHub repository."),
        ("Forensic Analysis","qa",["bulk_extractor","data_carving"],P,"How is bulk_extractor used for forensic analysis during ransomware investigations?","bulk_extractor is a forensic tool that scans disk images, memory dumps, or raw files and extracts structured data without parsing file system structures. Key extractors for ransomware investigation: email scanner extracts email addresses (useful for identifying phishing delivery and attacker communication); URL scanner extracts URLs (C2 addresses, download links, exfiltration destinations); network scanner extracts IP addresses, network packets, and Ethernet frames from page files and swap space; domain scanner identifies domain names in network traffic remnants; and the AES key finder can identify AES key schedules in memory dumps (potentially recovering encryption keys). Workflow: run bulk_extractor against the forensic image or memory dump; it creates output files (emails.txt, urls.txt, ip.txt, domain.txt) in a specified output directory; use the histogram files (email_histogram.txt, url_histogram.txt) to identify the most frequently occurring values; and cross-reference extracted artifacts with known IOCs and timeline data. Advantages over traditional analysis: bulk_extractor processes data at raw block level, finding artifacts in: unallocated space, slack space, page files, hibernation files, and even within encrypted containers (if the key was in memory when the dump was taken). It runs in parallel across CPU cores, processing large disk images relatively quickly."),
        ("Forensic Analysis","qa",["cyber_triage","automated_analysis"],P,"How do automated forensic triage tools like Cyber Triage help during ransomware incident response?","Cyber Triage (by Basis Technology, creators of Autopsy) provides automated endpoint analysis for incident response. For ransomware triage: it connects to live systems (via agent deployment) or analyzes forensic images; automatically collects and analyzes: running processes, network connections, startup items (scheduled tasks, services, Run keys), installed programs, web history, and user activity. Its automated scoring system flags suspicious items as: bad (known malicious based on hash or behavioral analysis), suspicious (anomalous based on heuristics and baselining), or good (known legitimate). For ransomware-specific analysis: it identifies known malware hashes, suspicious persistence mechanisms, unusual network connections, recently created services and scheduled tasks, and processes running from non-standard locations. Integration with YARA allows custom rule scanning, and VirusTotal integration provides hash-based reputation checking. Workflow: deploy Cyber Triage agents to all potentially affected systems; review the prioritized findings starting with items scored as 'bad'; use the timeline view to correlate suspicious activity across systems; and export IOCs for fleet-wide hunting. The tool reduces triage time from hours (manual KAPE + manual analysis) to minutes per system, enabling rapid scope assessment across large environments."),
        ("Forensic Analysis","qa",["reg_explorer","registry_analysis"],P,"What advanced Registry Explorer (Eric Zimmerman) features are most useful for ransomware investigation?","Registry Explorer provides GUI-based analysis with features specifically useful for ransomware investigation. Key features: bookmarking system allows marking suspicious registry keys and values across multiple hives for later review and reporting; the associated hives feature automatically loads related hives (SAM, SECURITY, SYSTEM, SOFTWARE, NTUSER.DAT) and presents a unified view; timestamp analysis shows last-modified timestamps for all keys, enabling timeline-based filtering to identify keys modified during the attack window; available plugins include: Amcache (program execution), SAM (user accounts), Network (network profiles and history), Services (installed services), and UserAssist (GUI program execution). For ransomware investigation specifically: filter all registry keys by last-written timestamp to identify keys modified during the attack window; examine Run keys and Services for persistence entries; check SAM hive for newly created local accounts; analyze Shimcache entries from the SYSTEM hive using the integrated parser; examine NTUSER.DAT for each user to find UserAssist entries showing attacker tool execution via GUI, RecentDocs showing files accessed, and TypedPaths showing Explorer address bar entries (network share paths the attacker manually navigated to). Export findings as text or JSON for inclusion in the forensic report."),
        ("Evidence Collection","qa",["evidence_storage","best_practices"],P,"What are the best practices for forensic evidence storage during and after a ransomware investigation?","Evidence storage best practices ensure integrity and availability throughout the investigation lifecycle. During investigation: store evidence on encrypted drives (BitLocker, LUKS) dedicated to case evidence; use a centralized evidence server with: access logging, NTFS permissions restricting access to authorized investigators, automatic hash verification on write, and RAID storage for redundancy. Naming conventions: use consistent file naming (CASE-YYYY-HOST-EvidenceType-YYYYMMDD, e.g., CASE-2026-DC01-MemoryDump-20260317). Storage requirements: estimate 2-3x the raw evidence size for working copies and processed output; memory dumps can range from 4-128GB per system; disk images can be hundreds of GB to several TB. Retention: maintain evidence for a minimum period aligned with: statute of limitations for potential criminal prosecution (typically 5-7 years for computer crimes); regulatory retention requirements (HIPAA 6 years, SOX 7 years); and civil litigation hold requirements (indefinite if litigation is pending or anticipated). Post-investigation: transfer evidence to long-term archival storage (LTO tape, offline encrypted drives in fire-rated safes, or secure cloud storage with immutable retention). Document the storage location, access procedures, and destruction date in the case file. When evidence is no longer required: perform documented destruction (disk wiping with certificate of destruction) to protect victim data."),
        ("Forensic Analysis","qa",["cloud_forensics_tools","azure_investigation"],P,"What tools are available for cloud forensic investigation during ransomware incidents involving Azure/M365?","Cloud forensic tools for Azure/M365 include: Microsoft 365 Unified Audit Log Search (compliance.microsoft.com): search and export audit logs across all M365 services; supports filtering by activity type, user, IP address, and date range; retention varies by license (90 days E3, 1 year E5). Azure AD Investigation tools: Azure AD Sign-in Logs and Audit Logs accessible via the Azure Portal or Microsoft Graph API; Conditional Access evaluation logs showing policy decisions for each authentication. Microsoft Cloud App Security (MCAS/Defender for Cloud Apps): provides detailed activity logs for cloud application usage, anomaly detection for impossible travel and mass downloads, and investigation timelines per user. PowerShell-based collection: the Exchange Online Management module enables: Search-UnifiedAuditLog for programmatic log retrieval, Get-MailboxFolderPermission for checking unauthorized access, and Get-InboxRule for identifying attacker-created forwarding rules. Third-party tools: HAWK (PowerShell module) automates M365 forensic data collection including mailbox analysis, app consent audits, and sign-in analysis; Sparrow (CISA) performs rapid M365 compromise assessment; and the CrowdStrike Reporting Tool for Azure collects and analyzes Azure AD activity for incident investigation."),
        ("Forensic Analysis","qa",["malware_triage","rapid_classification"],P,"What is the proper methodology for rapid malware triage when a ransomware binary is discovered during investigation?","Rapid malware triage follows a 15-minute structured approach for initial classification. Minutes 0-3 (File identification): compute SHA256/MD5 hashes and check VirusTotal for existing detections and family classification; check file size, type (PE, ELF, script), and compilation timestamp using pestudio or Detect It Easy; verify digital signature status (unsigned binaries from system directories are suspicious). Minutes 3-7 (Static indicators): extract strings using FLOSS (handles obfuscated strings) looking for: ransom note text, C2 URLs, cryptocurrency addresses, mutex names, file extensions, process kill lists, and service stop lists; examine PE imports for: encryption APIs (CryptoAPI, BCrypt), file system APIs (FindFirstFile, CreateFile, WriteFile), process manipulation APIs (OpenProcess, TerminateProcess), and network APIs (InternetOpen, HttpSendRequest); check PE sections for high entropy (packed/encrypted sections). Minutes 7-12 (Behavioral classification): based on static indicators, classify as: ransomware (encryption APIs + file enumeration + ransom note strings), loader/dropper (download APIs + process creation + minimal payload), RAT/beacon (network APIs + command processing + persistence), or tool (specific functionality like credential dumping or scanning). Minutes 12-15 (Documentation): record: file hash, family identification (if known), key capabilities, IOCs extracted, and recommended next steps (full sandbox analysis, blocking, or immediate containment)."),
        ("Forensic Analysis","qa",["file_recovery","data_restoration"],P,"What file recovery techniques are available after ransomware encryption and what determines their success?","File recovery success depends on the ransomware's encryption implementation and the file system state. Volume Shadow Copies: if any survive (check with vssadmin list shadows), they provide complete file versions from before encryption; ransomware typically deletes these, but some variants fail on non-system volumes. Previous versions: Windows File History or System Restore may have recoverable copies if these features were enabled. Unallocated space recovery: if the ransomware encrypts in-place (overwriting original data), recovery is limited; but if it creates new encrypted files and deletes originals, the original data may exist in unallocated space until overwritten. Partial encryption recovery: for ransomware using intermittent or partial encryption (LockBit, Royal), unencrypted file segments can be extracted; for header-only encryption, the bulk of file content remains intact and can be recovered by reconstructing the file header based on known format specifications. Cloud sync recovery: OneDrive, SharePoint, and Google Drive maintain version history; encrypted files synced to cloud may be recoverable by restoring previous versions through the cloud service's version history feature. Database recovery: SQL Server databases (.mdf/.ldf) may be partially recoverable using DBCC CHECKDB repair on the unencrypted portions. Backup recovery: the primary recovery method when encryption is complete; verify backup integrity before restoring and confirm the backup predates the intrusion (not just the encryption)."),
        ("Forensic Analysis","qa",["osint_investigation","threat_actor_research"],P,"How should investigators use OSINT to research the ransomware threat actor during an incident?","OSINT research on the threat actor provides intelligence that shapes the response strategy. Ransomware identification: upload ransom notes and encrypted samples to ID Ransomware for family identification; search for the ransom note text and file extension on VirusTotal, Twitter/X, and security forums for recent reports. Threat actor research: search the group name on MITRE ATT&CK for documented TTPs; review CISA advisories and Joint Cybersecurity Advisories for IOCs and mitigation guidance; check security vendor blogs (Mandiant, CrowdStrike, Sophos, Kaspersky) for detailed group analysis; and search BleepingComputer's ransomware topic for recent victim reports and decryptor availability. Leak site monitoring: check the group's Tor-based leak site (via RansomWatch or Ransomware.live aggregators) for: whether your organization is listed, the claimed data volume and type, the countdown timer deadline, and samples of stolen data. Negotiation intelligence: search for leaked negotiation chats from the group (some are published by researchers); understand the group's typical negotiation patterns, discount willingness, and decryptor reliability. Bitcoin/cryptocurrency: check the ransom wallet addresses on blockchain explorers (Blockchain.com, OXT) for transaction history indicating how many other victims have paid. Important: conduct all Tor-based research from isolated, non-attributable systems to prevent the threat actor from identifying your investigation activities."),
        ("Evidence Collection","qa",["live_response","incident_response"],P,"What live response data should be collected from a running Windows system before forensic imaging during ransomware response?","Live response collection captures volatile data lost when the system is powered off. Collection order (most volatile first): (1) System date/time: note any clock skew for timestamp correlation. (2) Running processes: tasklist /v /fo csv > processes.csv captures all processes with details; WMIC process list full provides additional metadata. (3) Network connections: netstat -anob captures all connections with owning process names; and arp -a captures the ARP cache showing recently communicated systems. (4) Logged-on users: quser and net session show interactive and network sessions. (5) Network shares: net share and net use show local and mapped shares. (6) Scheduled tasks: schtasks /query /fo csv /v exports all scheduled tasks. (7) Running services: sc query type= service state= all captures service status. (8) DNS cache: ipconfig /displaydns shows recently resolved domains (potential C2 indicators). (9) Clipboard contents: PowerShell Get-Clipboard may contain attacker-pasted commands. (10) Open files: net file shows files opened by network users; openfiles /query shows locally opened files. Run all collection commands from a pre-built USB drive using absolute paths to prevent evidence contamination. Redirect output to the USB drive or a network share, not the evidence system's disk. Document the collection process with timestamps and the analyst's identity for chain of custody."),
    ]

    for s,e,t,p,q,a in data:
        m(s,e,t,p,q,a)
    return ex


def main():
    os.makedirs(OUTPUT_DIR, exist_ok=True)
    total = 0

    print("Generating batch 3...")
    for name, func in [("cisa_stopransomware.jsonl", gen_cisa_batch3),
                        ("kaspersky_securelist.jsonl", gen_kaspersky_batch3),
                        ("dfir_report.jsonl", gen_dfir_batch3),
                        ("sans_dfir.jsonl", gen_sans_batch3)]:
        examples = func()
        count = append_jsonl(name, examples)
        total += count
        print(f"  Appended {count} to {name}")

    print(f"\nBatch 3 total: {total}")

    # Final counts
    for fname in ["cisa_stopransomware.jsonl", "kaspersky_securelist.jsonl",
                   "dfir_report.jsonl", "sans_dfir.jsonl"]:
        path = os.path.join(OUTPUT_DIR, fname)
        with open(path) as f:
            count = sum(1 for _ in f)
        print(f"  {fname}: {count}")

    total_all = 0
    for fname in ["cisa_stopransomware.jsonl", "kaspersky_securelist.jsonl",
                   "dfir_report.jsonl", "sans_dfir.jsonl"]:
        path = os.path.join(OUTPUT_DIR, fname)
        with open(path) as f:
            total_all += sum(1 for _ in f)
    print(f"\nGRAND TOTAL: {total_all}")


if __name__ == "__main__":
    main()
